const body = $json.body || {};
const fromSchedule = Boolean($json.timestamp || $json['Readable date']);
const list = (value, fallback) => Array.isArray(value) && value.length ? value : fallback;
const scheduleGeneratesImages = String($env.ODESSA_VISUAL_SCHEDULE_GENERATE_IMAGES || '').toLowerCase() === 'true';
const defaultGenerateImages = fromSchedule ? scheduleGeneratesImages : true;
const defaultReferences = [
  {
    source: 'safe_tango_live_style_seed',
    notes: 'Use high-level social live visual language only: vertical mobile framing, warm host energy, ring light, compact studio, LED accents, gift reaction moments, colorful overlays, direct camera presence. Do not copy any real creator identity.'
  },
  {
    source: 'safe_tango_live_environment_seed',
    notes: 'Look for generic environment inspiration: cozy bedroom live rooms, clean camera composition, soft glam styling, music request moments, moderation/quiet-chat scenes, and audience gratitude rituals without usernames, faces, logos or identifiable private spaces.'
  }
];
return [{ json: {
  objective: body.objective || 'Gerar biblioteca visual segura da persona Odessa/Juju para lives sociais inspirada em linguagem visual do Tango Live sem copiar pessoas reais.',
  mode: body.mode || (fromSchedule ? 'scheduled_visual_loop' : 'manual_webhook'),
  references: list(body.references, defaultReferences),
  seedPersona: body.seedPersona || 'Odessa/Juju, anfitria virtual brasileira para lives sociais, calorosa, proxima, expressiva, popular, segura e agradecida com a audiencia.',
  requestedBy: body.requestedBy || 'n8n visual asset generator',
  targetChannel: String(body.targetChannel || 'odessa-roadmap').replace(/^#/, ''),
  maxPrompts: Number(body.maxPrompts || 6),
  maxImages: Number(body.maxImages ?? (defaultGenerateImages ? 2 : 0)),
  generateImages: typeof body.generateImages === 'boolean' ? body.generateImages : defaultGenerateImages,
  imageProvider: body.imageProvider || $env.ODESSA_VISUAL_IMAGE_PROVIDER || 'auto',
  aspectRatio: body.aspectRatio || '9:16',
  imageSize: body.imageSize || '',
  imageModel: body.imageModel || $env.GEMINI_IMAGE_MODEL || 'gemini-2.5-flash-image',
  openaiImageModel: body.openaiImageModel || $env.OPENAI_IMAGE_MODEL || 'gpt-image-1',
  model: body.model || 'gemini-2.5-flash',
  temperature: Number(body.temperature || 0.58)
} }];

const webhookUrl = String($env.N8N_SLACK_WEBHOOK_URL || $env.SLACK_WEBHOOK_URL || '').trim();
const slackMessage = $json.slackMessage || {};
const visualRun = $json.visualRun || {};
const slackDispatch = { configured: Boolean(webhookUrl), sent: false, status: null, error: null };
if (webhookUrl && slackMessage.text) {
  try {
    const response = await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: slackMessage.text })
    });
    slackDispatch.sent = response.ok;
    slackDispatch.status = response.status;
    if (!response.ok) slackDispatch.error = await response.text();
  } catch (error) {
    slackDispatch.error = error.message || 'Slack webhook failed';
  }
}
return [{ json: { ok: true, visualRun, slackMessage, slackDispatch } }];
